DELIMITER $$
--
-- Procedures
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `calculate_engagement_scores` ()   BEGIN
    -- Update engagement scores for all articles
    -- Formula: (views * 1) + (shares * 5) + (comments * 3)
    UPDATE published_news
    SET engagement_score = (
        COALESCE(views, 0) * 1 + 
        COALESCE(shares, 0) * 5 + 
        COALESCE(comments_count, 0) * 3
    );
    
    -- Auto-mark top 10 articles from last 7 days as trending
    UPDATE published_news
    SET is_trending = 0;
    
    UPDATE published_news
    SET is_trending = 1
    WHERE id IN (
        SELECT id FROM (
            SELECT id
            FROM published_news
            WHERE published_at >= DATE_SUB(NOW(), INTERVAL 7 DAY)
            ORDER BY engagement_score DESC
            LIMIT 10
        ) AS trending_articles
    );
    
    -- Auto-expire breaking news after 24 hours
    UPDATE published_news
    SET is_breaking = 0
    WHERE is_breaking = 1 
    AND (
        breaking_until IS NOT NULL AND breaking_until < NOW()
        OR published_at < DATE_SUB(NOW(), INTERVAL 24 HOUR)
    );
    
    -- Auto-expire flash reports after 2 hours
    UPDATE published_news
    SET is_flash = 0
    WHERE is_flash = 1 
    AND (
        flash_until IS NOT NULL AND flash_until < NOW()
        OR published_at < DATE_SUB(NOW(), INTERVAL 2 HOUR)
    );
END$$

DELIMITER ;

