--
-- Table structure for table `department_access`
--

CREATE TABLE `department_access` (
  `id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL COMMENT 'User receiving access',
  `department_id` int(11) NOT NULL COMMENT 'Department they can access',
  `granted_by` int(11) DEFAULT NULL COMMENT 'User who granted this access',
  `granted_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `department_visibility`
--

CREATE TABLE `department_visibility` (
  `id` int(11) NOT NULL,
  `source_dept_id` int(11) NOT NULL COMMENT 'Department that can see content',
  `target_dept_id` int(11) NOT NULL COMMENT 'Department whose content is visible',
  `granted_by` int(11) DEFAULT NULL COMMENT 'User who granted this access',
  `granted_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `external_articles`
--

CREATE TABLE `external_articles` (
  `id` int(11) NOT NULL,
  `title` varchar(500) NOT NULL,
  `content` text DEFAULT NULL,
  `description` text DEFAULT NULL,
  `category` varchar(100) DEFAULT NULL,
  `source` varchar(255) DEFAULT NULL,
  `author` varchar(255) DEFAULT NULL,
  `published_at` datetime DEFAULT NULL,
  `external_url` varchar(500) DEFAULT NULL,
  `image_url` varchar(500) DEFAULT NULL,
