  `external_url` varchar(500) DEFAULT NULL,
  `source_type` varchar(50) DEFAULT 'manual',
  `is_pushed` tinyint(1) DEFAULT 1,
  `is_update` tinyint(1) DEFAULT 0 COMMENT '1 = This is an update to another article',
  `update_type` enum('correction','follow-up','breaking-update','clarification','developing') DEFAULT NULL COMMENT 'Type of update',
  `update_number` int(11) DEFAULT 1 COMMENT 'Update sequence number',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `published_at` datetime DEFAULT current_timestamp(),
  `views` int(10) UNSIGNED DEFAULT 0 COMMENT 'Number of views',
  `shares` int(10) UNSIGNED DEFAULT 0 COMMENT 'Number of shares',
  `comments_count` int(10) UNSIGNED DEFAULT 0 COMMENT 'Number of comments',
  `engagement_score` int(10) UNSIGNED DEFAULT 0 COMMENT 'Calculated engagement score',
  `is_breaking` tinyint(1) DEFAULT 0 COMMENT 'Is this breaking news?',
  `is_flash` tinyint(1) DEFAULT 0 COMMENT 'Is this a flash report?',
  `is_featured` tinyint(1) DEFAULT 0 COMMENT 'Is this a featured article?',
  `is_trending` tinyint(1) DEFAULT 0 COMMENT 'Is this currently trending?',
  `priority` enum('low','normal','high','urgent') NOT NULL DEFAULT 'normal',
  `featured_order` int(11) DEFAULT 0 COMMENT 'Order for featured articles (lower = higher priority)',
  `breaking_until` datetime DEFAULT NULL COMMENT 'Breaking news expires at this time',
  `flash_until` datetime DEFAULT NULL COMMENT 'Flash report expires at this time',
  `author` varchar(255) DEFAULT NULL COMMENT 'Article author',
  `source` varchar(255) DEFAULT NULL COMMENT 'Article source',
  `priority_order` tinyint(3) UNSIGNED GENERATED ALWAYS AS (case `priority` when 'urgent' then 1 when 'high' then 2 when 'normal' then 3 when 'low' then 4 else 3 end) VIRTUAL,
  `decay_score` decimal(12,4) GENERATED ALWAYS AS (`views` / (timestampdiff(HOUR,`published_at`,current_timestamp()) + 2)) VIRTUAL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

