(223, 177, NULL, 'hreads of Resilience: Ukrainian Fashion Exhibit Celebrates Culture and Innovation in the Philippines', 'The Embassy of Ukraine in the Philippines recently unveiled a remarkable fashion exhibit, aptly titled \"Ukrainian Threads of Resilience.\" This event, held in the vibrant heart of Manila, served as a powerful cultural exchange that highlighted Ukraine\'s rich heritage, innovative spirit, and unyielding resilience. Through a stunning array of garments and accessories, the exhibit captured the essence of a nation that, despite facing significant challenges, continues to thrive and express its identity through the art of fashion. The display was not just about clothing; it was a narrative woven from threads of history, creativity, and a shared human experience.\r\n\r\nAt the heart of the exhibition was a diverse collection that showcased the evolution of Ukrainian design, blending traditional craftsmanship with contemporary aesthetics. Designers featured in the showcase drew inspiration from Ukraine’s folklore, landscapes, and vibrant culture, creating pieces that resonate on both a personal and collective level. Each garment told a story, reflecting the deep-rooted traditions of the past while boldly embracing modern techniques and materials. This fusion of old and new symbolizes Ukraine\'s journey—a nation that honors its heritage while looking forward to a future filled with possibilities. The exhibit facilitated meaningful dialogue not only about fashion but also about resilience and innovation, connecting the Filipino audience to the profound narratives embedded in each piece.\r\n\r\nThe “Ukrainian Threads of Resilience” exhibit ultimately served as a testament to the enduring power of creativity as a tool for cultural diplomacy. It emphasized the importance of collaboration and understanding between nations, showcasing how art can bridge gaps and foster connections. As attendees explored the intricacies of each design, they were reminded that culture transcends borders, allowing shared experiences and mutual respect to flourish. In a world often marked by division, the exhibit stood as a beacon of hope, illustrating how fashion can unite us in our shared humanity and inspire us to celebrate both our differences and our commonalities. Through this lens, the Embassy of Ukraine not only showcased its vibrant culture but also invited the Philippines to join in a collective celebration of resilience and creativity.', 57, 1, 10, 'uploads/thumb_699ea5a3ebbb30.97191252.png', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-26 02:30:34', '2026-02-26 02:30:34', '2026-02-26 10:30:34', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(224, 176, NULL, 'Global Spam Email Attacks Surge by 15%, Warns Kaspersky Report', 'In a startling revelation, the latest report from Kaspersky highlights a significant 15% increase in spam email attacks globally. This alarming trend underscores the escalating threat posed by cybercriminals who exploit the convenience of email communication. As businesses and individuals increasingly rely on digital correspondence, the sophistication and volume of spam attacks have also surged, prompting a call to action for enhanced cybersecurity measures across all sectors.\r\n\r\nThe report outlines that these spam emails are not just simple nuisances; they often serve as gateways for more severe threats, such as phishing schemes and malware distribution. Cybercriminals have become adept at crafting convincing emails that lure unsuspecting recipients into revealing sensitive information or downloading malicious software. This rise in spam attacks poses an urgent challenge for organizations, which must remain vigilant in their defenses. Kaspersky emphasizes the need for comprehensive email security solutions and user education to combat this growing menace effectively.\r\n\r\nFurthermore, the report highlights the implications of increased spam attacks on both personal and professional fronts. For businesses, the rise in spam can lead to financial losses, data breaches, and damage to reputation. For individuals, falling victim to spam can result in identity theft and significant emotional distress. As such, Kaspersky urges users to adopt best practices, such as scrutinizing email sources, using robust spam filters, and maintaining updated security software. The findings serve as a critical reminder of the ever-evolving landscape of cyber threats and the importance of proactive measures in safeguarding against them.', 54, 1, 10, 'uploads/thumb_699ea43e106196.22706150.webp', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-26 02:30:36', '2026-02-26 02:30:36', '2026-02-26 10:30:36', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(225, 175, NULL, 'Apple Introduces Global Age Verification System to Enhance Online Child Safety', 'In a significant move towards bolstering online child safety, Apple has rolled out a global age verification system. This initiative aims to comply with evolving regulations and standards concerning the protection of minors in the digital realm. The system is designed to ensure that users are of appropriate age before accessing certain content or services, thereby fostering a safer online environment for children and adolescents. As the internet becomes increasingly integral to daily life, the need for robust mechanisms to safeguard young users has never been more critical.\r\n\r\nThe new age verification system leverages advanced technologies to ascertain a user\'s age without compromising their privacy. By utilizing methods such as facial recognition and secure document verification, Apple seeks to create a seamless experience for users while ensuring compliance with local and international laws. This multifaceted approach not only protects children from inappropriate content but also provides parents with greater peace of mind. As digital platforms face increasing scrutiny over their practices, Apple\'s proactive stance underscores its commitment to responsible technology use.\r\n\r\nFurthermore, Apple\'s age verification system aligns with global trends in online safety regulations, reflecting a broader industry shift towards greater accountability. With governments and organizations around the world advocating for stricter controls to protect minors, Apple\'s initiative sets a standard for other tech companies to follow. By prioritizing user safety and adhering to legal requirements, Apple not only enhances its reputation but also plays a vital role in shaping a safer digital landscape for future generations. As the company continues to innovate, its efforts in age verification signal a promising step forward in the ongoing quest for online child safety.', 54, 1, 10, 'uploads/thumb_699ea273b1c248.19675615.jpg', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-26 02:30:38', '2026-02-26 02:30:38', '2026-02-26 10:30:38', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(226, 174, NULL, 'Kylie Padilla says she will leave PH if father Robin Padilla runs for VP', 'Kylie Padilla said that she would leave the Philippines should her father, Sen. Robin Padilla heed the call for him to run for vice president in the 2028 elections, but she was quick to make a clarification, saying her remark was not meant to insult her dad.\r\n\r\nDuring a recent screening for her film “The Lotto Winner,” the actress was asked about her reaction to the actor-politician’s statement that he would willingly run for higher office if former President Rodrigo Duterte would personally ask him to do so.\r\n\r\nThe former chief executive is currently incarcerated at The Hague in the Netherlands to answer to charges of crimes against humanity over his brutal war on drugs. Meanwhile, his daughter, Vice President Sara Duterte, has just recently announced her intention to run for president in the 2028 polls.\r\n\r\nReacting to Robin’s remarks, Kylie said while laughing: “Aalis na ako ng Pilipinas (I would leave the Philippines).” Turning serious, she added, “I trust in my father’s judgment.”\r\n\r\nKylie’s response immediately drew various reactions on social media, which prompted her to issue a clarification through her Instagram Stories on Tuesday, Feb. 24.\r\n\r\n“I only meant that aalis po ako ng Pilipinas kasi gusto ko ng tahimik na buhay (I would leave the Philippines because I want a peaceful life),” she said. “It was not a comment to insult my father because I trust in his judgment and all the good he is doing for this country.”\r\n\r\n“But I think it is also my right to know what kind of life I want to live. And that is a quiet peaceful life. ‘Yun lang po (That’s it). Xoxo,” she said.\r\n\r\nKylie Padilla says \'leaving PH\' remark not meant to insult dad Robin Padilla\r\n\r\n“Please do not take my statement and use it against my father,” she appealed. “I only made the comment out of my desire to live a calm, peaceful and quiet life… I love him and only wish for him to be happy and safe always.”\r\n\r\nRobin has yet to comment on the matter as of this writing.', NULL, 1, 13, 'uploads/thumb_699e9dfeab1021.98406999.png', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-26 02:30:39', '2026-02-26 02:30:39', '2026-02-26 10:30:39', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(227, 173, NULL, 'NBA: Wendell Carter Jr. scores late winner as Magic edge Lakers', 'LOS ANGELES — Wendell Carter Jr. made a go-ahead putback with 6.7 seconds to play, Paolo Banchero scored 36 points and the Orlando Magic finished a strong West Coast trip with a 110-109 victory over the Los Angeles Lakers in the NBA on Tuesday night.\r\n\r\nLeBron James missed a fallaway 3-point attempt on the final shot by the Lakers, who went 4-4 on a disappointing homestand spanning the NBA All-Star break. Los Angeles has lost four of six and fallen into sixth place in the West, repeatedly failing to beat playoff-caliber teams.\r\n\r\nDesmond Bane scored 22 points and Carter had 20 points and 12 rebounds for the Magic, who have won six of eight overall after taking three of four on the road out of the break. That surge — capped by their fourth consecutive win over the Lakers — has moved the Magic within a half-game of sixth place in the Eastern Conference\r\n\r\nOrlando rallied from an early double-digit deficit to take a five-point lead with 5 1/2 minutes left, but Rui Hachimura hit a tiebreaking 3-pointer with 2:14 to play for the Lakers. Bane drilled a go-ahead 3 with 34.6 seconds left, but Doncic found James under the basket for a dunk to reclaim the lead.', 56, 1, 13, 'uploads/thumb_699e99b01ae9c7.82974660.jpg', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-26 02:30:41', '2026-02-26 02:30:41', '2026-02-26 10:30:41', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(228, 172, NULL, '3 more Discaya luxury vehicles sold for P25.7-M', 'MANILA, Philippines — Three more luxury vehicles linked to the contractor couple Sarah and Pacifico Discaya were sold at the public auction of the Bureau of Customs (BOC) on Wednesday, which raised a total revenue collection of P25.7 million. \r\n\r\nOf the 12 cars for auction, seven were owned by the Discayas, who were tagged in anomalous flood control and other infrastructure projects.\r\n\r\nA 2024 Lincoln Navigator was sold to Cantinetta Espresso Concepts, represented by Gilbert Leoncio, for P6,950,000 while the 2022 Bentley Bentayga was sold to TDY Consumer Goods Trading for P12,178,174.15. \r\n\r\nA 2022 Cadillac Escalade ESV was sold to Igorot Stone Kingdom, represented by Pio Velasco, for P6,623,000. The Baguio City-based theme park once again successfully bidded for a Discaya car as it also won the bid for a Rolls Royce Cullinan at the agency’s auction two weeks ago. \r\n\r\nWith this auction, the BOC raised a total collection of P25,771,374.15, inclusive of registration fees. The agency earlier said that the revenue will be remitted to the Bureau of Treasury to fund government projects. \r\n\r\nThe following cars were not auctioned:\r\nFerrari SF90 Stradale (Mansory) 2024\r\nRolls Royce Phantom 2023\r\nMercedes-Benz G650 V12 Biturbo 2022\r\nBMW XM 2024\r\nLexus LX570 2018\r\nGMC Yukon Denali 2022\r\nCadillac Escalade 2021\r\nMaserati Levante Modena 2022\r\nGMC Yukon XL Denali 2022.', 46, 1, 13, 'uploads/thumb_699e9821ab1de3.49290977.png', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-26 02:30:45', '2026-02-26 02:30:45', '2026-02-26 10:30:45', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(229, 171, NULL, 'Rights groups: EDSA@40 uniquely meaningful as Duterte ICC case continues', 'MANILA, Philippines – Rise Up for Life and for Rights and Karapatan said that the 40th anniversary of Edsa People Power revolution carries deeper meaning, with ongoing confirmation of charges hearings in the case against former president Rodrigo Duterte at the International Criminal Court in The Hague.\r\n\r\n“Ang paggunita ngayon ng EDSA@40 ay makasaysayan at mahalaga sa mga pamilya ng biktima ng war on drugs dahil sa kasalukuyang confirmation of charges hearing sa kaso ni Duterte na krimen laban sa sangkatauhan,” said Rise Up for Life and for Rights in a statement.\r\n\r\n(“Today’s commemoration of EDSA@40 is historic and important for the families of victims of the war on drugs due to the ongoing confirmation of charges hearing in Duterte’s case for crimes against humanity.”)\r\n\r\nThe rights group emphasized that the 1986 People Power revolution proved Filipinos could end oppression by standing together.\r\n\r\nThe group believes this anniversary highlights how collective action remains the most effective way to protect the rights and dignity of the people.\r\n\r\nKarapatan, in a statement, also said the 40th anniversary of the Edsa People Power revolution is a pivotal moment for justice, linking the spirit of 1986 revolution to the legal battle against former President Duterte.\r\n\r\nLlore Pasco, mother of drug war victims and a representative of the advocacy group Rise Up for Life and for Rights, attended the proceedings in The Hague. \r\n\r\n“It’s horrifying to hear Duterte’s voice,” Pasco stated in Filipino, emphasizing that the loss of her children was no joking matter.\r\n\r\n“He should pay for his crimes,” she added.\r\n\r\nThe prosecution also shared the “PRRD list,” widely reported in the media as the “Kill List,” to show that Duterte was criminally responsible for the killings and attempted murder of 59 people.\r\n\r\nAccording to Rubylin Litao, national coordinator of Rise Up for Life and for Rights, the “PRRD list” and police orders to kill suspects prove that the drug war was an organized, bloody policy under Duterte.\r\n\r\n“We are hoping that the ICC will confirm all the charges against Duterte and the trial will proceed soon,” said Litao.\r\n\r\nThe confirmation of charges hearings are scheduled until February 26 and 27, at which the court will determine if there is sufficient evidence to move forward with a full trial for Duterte.\r\n\r\nThe commemoration of the 40th anniversary of Edsa People Power revolution, also coincides with the third leg of “Trillion Peso March,” a large-scale protest in response to the alleged corruption in “ghost” flood control infrastructure projects unveiled in August 2025.\r\n\r\nThe previous mass demonstrations were held on September 21 and November 30 last year.', 46, 1, 13, 'uploads/thumb_699e9763a0e3b7.55000777.png', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-26 02:30:48', '2026-02-26 02:30:48', '2026-02-26 10:30:48', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(230, 182, 226, 'Kylie Padilla Explains Viral Comment About Moving Abroad', 'Actress Kylie Padilla addressed her recent comment about leaving the Philippines if her father, Senator Robin Padilla, decides to run for vice president in the 2028 elections. She clarified on social media that her statement was not meant to offend or criticize him, but simply reflected her personal desire for a quieter and more peaceful life. Kylie emphasized that she trusts her father’s judgment and respects the work he is doing for the country, but she also believes she has the right to choose the kind of life she wants to live.\r\n\r\nEarlier, Kylie had jokingly said in an interview that she would leave the country if her father pursued the vice presidency. Meanwhile, Robin Padilla expressed his willingness to run in 2028 if asked by former President Rodrigo Duterte, saying he would follow Duterte’s lead out of loyalty and shared ideology. He also described the vice presidency as a role focused largely on advocacy. As this unfolds, Kylie continues to focus on her career, currently promoting her film The Lotto Winner alongside Albert Martinez and Sienna Stevens.', NULL, 1, 8, 'uploads/thumb_699fb310480fe.webp', NULL, NULL, 'manual', 1, 1, '', 1, '2026-02-26 02:53:04', '2026-02-26 02:53:04', '2026-02-26 10:53:04', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(231, 188, NULL, 'Duterte argument: Killings done in self-defense', 'In the confirmation of charges hearing at the International Criminal Court (ICC), the defense team of former Philippine President Rodrigo Duterte argued that the killings during his administration\'s anti-drug operations were justified as acts of self-defense. \r\n\r\nLead counsel Nicholas Kaufman downplayed the scale of the killings, claiming they were \"minimal\" and not \"widespread\" as alleged by the prosecution. He contended that the drug war victims were not part of the \"civilian population\" as they were drug suspects who allegedly had guns.\r\n\r\nKaufman criticized the prosecution for interpreting the term \"neutralization\" as a \"euphemism for murder\" in the government\'s policy guidelines. He insisted that the prosecution failed to establish a direct causal link between Duterte\'s statements and the deaths.\r\n\r\nThe defense also refuted the prosecution\'s interpretation of \"neutralization,\" citing a statement by former police chief Ronald \"Bato\" dela Rosa that it was meant to \"instill fear\" in drug users, not necessarily kill them. Kaufman portrayed the drug war as a \"not a refined policy\" by referring to confessions of witnesses who described random killings to meet quotas.\r\n\r\nOverall, the Duterte defense team sought to portray the killings as acts of self-defense by law enforcement, rather than a widespread and systematic attack on the civilian population as alleged by the prosecution.', 50, 1, 13, 'uploads/thumb_69a100b8279b88.38850391.png', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-27 06:33:11', '2026-02-27 06:33:11', '2026-02-27 14:33:11', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(232, 187, NULL, 'Phivolcs: Mayon Volcano emits flowing lava, volcanic ash', 'MANILA, Philippines — Lava effusion with lava flow on three gullies and minor ash emissions that generated plume were observed from Mayon Volcano in the province of Albay, the state volcanology bureau said on Thursday. In its latest 24-hour observation summary, the Philippine Institute of Volcanology and Seismology (Phivolcs) reported that lava descended 3.8 kilometers\r\n\r\n---\r\nAuthor: Inquirer\r\nSource: Inquirer\r\nPublished: February 26, 2026', 98, 1, 8, 'uploads/thumb_699fbf2619dfc4.14059717.jpg', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-27 06:33:14', '2026-02-27 06:33:14', '2026-02-27 14:33:14', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(233, 186, NULL, 'Is the War on Saturated Fat Built on Weak Evidence?', 'For more than 60 years, mainstream nutrition advice has warned that saturated fat increases heart disease risk and should be replaced with polyunsaturated fats or low-fat products. This guidance largely stems from the Seven Countries Study led by Ancel Keys in 1958, which reported a correlation between saturated fat consumption and heart disease mortality. Researcher J. Manuel González argues that the study’s design was seriously flawed, citing its limited sample, exclusion of women, selective populations, and insufficient control of other risk factors. Despite these shortcomings, its conclusions became deeply embedded in public health policy, driving major changes in global food production and consumer habits.\r\n\r\nGonzález also highlights the Minnesota Coronary Experiment, a large randomized controlled trial conducted between 1968 and 1973, whose full findings were later published in The BMJ in 2016. The recovered data showed no clear mortality benefit from replacing saturated fats with polyunsaturated fats and even suggested higher death rates among participants who experienced the greatest cholesterol reductions. He argues that these results cast doubt on the long-standing lipid hypothesis and raise questions about the magnitude of benefit from cholesterol-lowering drugs in primary prevention. Ultimately, González maintains that the science surrounding saturated fat remains unsettled and calls for more rigorous, transparent research to inform balanced dietary recommendations.', 53, 1, 8, 'uploads/thumb_699fbe6bead037.35516157.jpg', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-27 06:33:19', '2026-02-27 06:33:19', '2026-02-27 14:33:19', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(234, 185, NULL, '‘Blood Moon’ to Be Visible in Manila for Nearly an Hour', 'A total lunar eclipse will be observable across Manila and other parts of the Philippines on March 3, the Philippine Atmospheric, Geophysical and Astronomical Services Administration (Pagasa) announced. The celestial event will run from 7:04 p.m. to 8:03 p.m., with peak visibility at 7:34 p.m. The phenomenon takes place during a full moon when the Earth aligns directly between the Sun and the Moon, casting a shadow that gradually covers the lunar surface.\r\n\r\nAt its height, the eclipse will completely obscure the Moon, creating what is commonly known as a “blood moon” due to its reddish hue caused by Earth’s atmosphere bending and scattering sunlight. Aside from the Philippines, the eclipse will also be seen in parts of Eastern Asia, Australia, the Central Pacific, and much of the Americas. Pagasa noted that the event is safe to watch without special equipment, although binoculars can provide a clearer view.', 95, 1, 8, 'uploads/thumb_699fbcee263d52.80475761.webp', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-27 06:33:21', '2026-02-27 06:33:21', '2026-02-27 14:33:21', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(235, 184, NULL, 'Lady Spikers Lean on Rookie Spark to Down UP', 'Rookie Mikee Santos delivered a strong performance to lift the De La Salle Lady Spikers to a dominant 25-12, 25-15, 25-19 win over the UP Fighting Maroons in the UAAP Season 88 women’s volleyball tournament. With leading scorer Shevana Laput out due to illness, Santos rose to the occasion, tallying eight kills and two blocks for 10 points to help La Salle remain unbeaten at 3-0. She shared that she stayed focused on executing what their coaches have emphasized in training and embraced the opportunity to support the team’s veterans.\r\n\r\nAmie Provido commended the rookies for their composure and eagerness to contribute, highlighting their confidence despite being new to the collegiate stage. Santos also credited senior leaders such as Angel Canino for inspiring and guiding her in her first UAAP campaign. Determined to sustain their momentum, Santos said the Lady Spikers will intensify their preparations ahead of their upcoming showdown with Ateneo.', NULL, 1, 8, 'uploads/thumb_699fbc278822c0.12606530.jpg', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-27 06:33:24', '2026-02-27 06:33:24', '2026-02-27 14:33:24', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL),
(236, 183, NULL, 'Duterte Declines to Attend ICC Custody Review in The Hague', 'Former president Rodrigo Duterte has waived his right to attend the upcoming annual review of his detention before Pre-Trial Chamber I of the International Criminal Court (ICC), according to a signed filing dated Feb. 23. In the waiver, Duterte said he understood the legal implications of his decision and would allow his legal counsel to represent him. He remains detained at the ICC facility in The Hague following his arrest in March 2025 over allegations of crimes against humanity linked to his administration’s anti-drug campaign. The review, required under the court’s rules, will determine whether his continued detention remains necessary. Previous requests for temporary release were denied, and the ICC has affirmed its jurisdiction over the case despite Duterte’s objections.\r\n\r\nAs proceedings continue, the prosecution has cited the alleged involvement of former police chief and Senator Ronald Dela Rosa in the anti-drug operations under scrutiny. Meanwhile, Catholic priest and humanitarian advocate Flavie Villanueva expressed hope that justice will be served for victims of extrajudicial killings. Separate allegations of bribery involving ICC investigators have also surfaced, naming several public figures, but those implicated — including former senator Antonio Trillanes IV — have denied the claims and signaled plans to take legal action.', 48, 1, 8, 'uploads/thumb_699fb95f1083b3.32709505.jpg', NULL, NULL, 'manual', 1, 0, NULL, 1, '2026-02-27 06:34:01', '2026-02-27 06:34:01', '2026-02-27 14:34:01', 0, 0, 0, 0, 0, 0, 0, 0, 'normal', 0, NULL, NULL, NULL, NULL);

--
-- Triggers `published_news`
--
DELIMITER $$
CREATE TRIGGER `before_breaking_news_insert` BEFORE INSERT ON `published_news` FOR EACH ROW BEGIN
    -- If marked as breaking and no expiry set, auto-set to 24 hours
    IF NEW.is_breaking = 1 AND NEW.breaking_until IS NULL THEN
        SET NEW.breaking_until = DATE_ADD(NOW(), INTERVAL 24 HOUR);
    END IF;
    
    -- If marked as flash and no expiry set, auto-set to 2 hours
    IF NEW.is_flash = 1 AND NEW.flash_until IS NULL THEN
        SET NEW.flash_until = DATE_ADD(NOW(), INTERVAL 2 HOUR);
    END IF;
    
    -- Calculate initial engagement score
    SET NEW.engagement_score = (
        COALESCE(NEW.views, 0) * 1 + 
        COALESCE(NEW.shares, 0) * 5 + 
        COALESCE(NEW.comments_count, 0) * 3
    );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `before_breaking_news_update` BEFORE UPDATE ON `published_news` FOR EACH ROW BEGIN
    -- Recalculate engagement score on update
    SET NEW.engagement_score = (
        COALESCE(NEW.views, 0) * 1 + 
        COALESCE(NEW.shares, 0) * 5 + 
        COALESCE(NEW.comments_count, 0) * 3
    );
    
    -- If is_breaking changed from 0 to 1 and no expiry set
    IF NEW.is_breaking = 1 AND OLD.is_breaking = 0 AND NEW.breaking_until IS NULL THEN
        SET NEW.breaking_until = DATE_ADD(NOW(), INTERVAL 24 HOUR);
    END IF;
    
    -- If is_flash changed from 0 to 1 and no expiry set
    IF NEW.is_flash = 1 AND OLD.is_flash = 0 AND NEW.flash_until IS NULL THEN
        SET NEW.flash_until = DATE_ADD(NOW(), INTERVAL 2 HOUR);
    END IF;
END
$$
DELIMITER ;

